args.sparql:
SELECT ?edition ?year WHERE {
  ?series wdt:P31 wd:Q1363275 .
  ?edition wdt:P361 ?series ;
           wdt:P585 ?year ;
           wdt:P122 wd:Q334634 ;
           wdt:P122 wd:Q650840 .
  FILTER(?year >= 1978)
}
LIMIT 10

SELECT ?edition ?game ?duration WHERE {
  ?series wdt:P31 wd:Q1363275 .
  ?edition wdt:P361 ?series ;
           wdt:P122 wd:Q334634 ;
           wdt:P122 wd:Q650840 ;
           wdt:P580 ?startDate .
  FILTER(YEAR(?startDate) >= 1978)
  ?game wdt:P361 ?edition ;
        wdt:P122 wd:Q334634 ;
        wdt:P122 wd:Q650840 ;
        wdt:P7290 ?duration .
}
ORDER BY DESC(?duration)
LIMIT 1
